diff --git a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
index 456f5086309c..832dbcf7143f 100644
--- a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
+++ b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
@@ -1141,6 +1141,8 @@ void State::addInfoFor(BasicBlock &BB) {
         break;
       [[fallthrough]];
     case Intrinsic::abs:
+    case Intrinsic::usub_sat:
+    case Intrinsic::ssub_sat:
       WorkList.push_back(FactOrCheck::getInstFact(DT.getNode(&BB), &I));
       break;
     }
@@ -1390,6 +1392,46 @@ static std::optional<bool> checkCondition(CmpInst::Predicate Pred, Value *A,
                                           ConstraintInfo &Info) {
   LLVM_DEBUG(dbgs() << "Checking " << *CheckInst << "\n");

+  // Handle saturating subtraction: usub.sat(X, C) <= X when C >= 0.
+  // If comparing usub.sat(X, C) < Y (or <=), we can use X < Y (or <=) instead.
+  if (auto *Sat = dyn_cast<SaturatingInst>(A)) {
+    if (Sat->getIntrinsicID() == Intrinsic::usub_sat) {
+      Value *X = Sat->getOperand(0);
+      Value *C = Sat->getOperand(1);
+      if (auto *CI = dyn_cast<ConstantInt>(C)) {
+        if (!CI->isNegative()) {
+          // usub.sat(X, C) <= X, so if X < Y, then usub.sat(X, C) < Y.
+          switch (Pred) {
+          case CmpInst::ICMP_ULT:
+          case CmpInst::ICMP_ULE:
+            if (auto Result = checkCondition(Pred, X, B, CheckInst, Info))
+              return Result;
+            break;
+          default:
+            break;
+          }
+        }
+      }
+    } else if (Sat->getIntrinsicID() == Intrinsic::ssub_sat) {
+      Value *X = Sat->getOperand(0);
+      Value *C = Sat->getOperand(1);
+      if (auto *CI = dyn_cast<ConstantInt>(C)) {
+        if (!CI->isNegative()) {
+          // ssub.sat(X, C) <= X, so if X <s Y, then ssub.sat(X, C) <s Y.
+          switch (Pred) {
+          case CmpInst::ICMP_SLT:
+          case CmpInst::ICMP_SLE:
+            if (auto Result = checkCondition(Pred, X, B, CheckInst, Info))
+              return Result;
+            break;
+          default:
+            break;
+          }
+        }
+      }
+    }
+  }
+
   auto R = Info.getConstraintForSolving(Pred, A, B);
   if (R.empty() || !R.isValid(Info)){
     LLVM_DEBUG(dbgs() << "   failed to decompose condition\n");
@@ -1425,7 +1467,6 @@ static std::optional<bool> checkCondition(CmpInst::Predicate Pred, Value *A,

   return std::nullopt;
 }
-
 static bool checkAndReplaceCondition(
     ICmpInst *Cmp, ConstraintInfo &Info, unsigned NumIn, unsigned NumOut,
     Instruction *ContextInst, Module *ReproducerModule,
@@ -1898,6 +1939,27 @@ static bool eliminateConstraints(Function &F, DominatorTree &DT, LoopInfo &LI,
         AddFact(Pred, MinMax, MinMax->getRHS());
         continue;
       }
+
+      // Handle saturating subtraction: usub.sat(X, C) <= X and ssub.sat(X, C) <= X
+      // when C >= 0.
+      if (auto *Sat = dyn_cast<SaturatingInst>(CB.Inst)) {
+        if (Sat->getIntrinsicID() == Intrinsic::usub_sat ||
+            Sat->getIntrinsicID() == Intrinsic::ssub_sat) {
+          Value *X = Sat->getOperand(0);
+          Value *C = Sat->getOperand(1);
+          // Only add the fact if C is a non-negative constant.
+          if (auto *CI = dyn_cast<ConstantInt>(C)) {
+            if (!CI->isNegative()) {
+              // For usub.sat, use unsigned comparison; for ssub.sat, use signed.
+              if (Sat->getIntrinsicID() == Intrinsic::usub_sat)
+                AddFact(CmpInst::ICMP_ULE, Sat, X);
+              else
+                AddFact(CmpInst::ICMP_SLE, Sat, X);
+            }
+          }
+          continue;
+        }
+      }
     }

     Value *A = nullptr, *B = nullptr;

